function getKyivDateTimeFormatted() {
  const kyivTime = new Date().toLocaleString("en-US", { timeZone: "Europe/Kyiv" });
  const kyivDate = new Date(kyivTime);

  const year = kyivDate.getFullYear();
  const month = String(kyivDate.getMonth() + 1).padStart(2, '0');
  const day = String(kyivDate.getDate()).padStart(2, '0');
  const hour = String(kyivDate.getHours()).padStart(2, '0');
  const minute = String(kyivDate.getMinutes()).padStart(2, '0');
  const second = String(kyivDate.getSeconds()).padStart(2, '0');

  return `${year}-${month}-${day}T${hour}:${minute}:${second}`;
}

return [{ json: { kyivDateTime: getKyivDateTimeFormatted() } }];

// Retrieve the output string from the previous AI Agent or Chat Model node
// Note: Path may vary based on the specific LLM integration
const rawOutput = $json.output || ($json.choices && $json.choices[0].message.content);

if (!rawOutput) {
  return { error: "No input data found." };
}

// Extract potential JSON block using regex (matches from the first '{' to the last '}')
const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);

if (jsonMatch) {
  try {
    // Parse and return the extracted JSON payload
    const parsedJson = JSON.parse(jsonMatch[0]);
    return parsedJson;
  } catch (error) {
    // Handle parsing failures gracefully
    return { error: "Failed to parse JSON.", details: error.message };
  }
}

// Return error if no valid JSON structure is detected in the payload
return { error: "No JSON object found in the output." };

// Retrieve incoming data from the "Parse AI JSON" node
const newData = $('Parse AI JSON').first().json;

// Fetch existing page metadata from "Get Current Data"
const existingPage = $('Get Current Data').first().json;

// Validate existing page properties
if (!existingPage || !existingPage.properties) {
  throw new Error("Validation Error: Missing properties in 'Get Current Data' output.");
}

// Initialize final state with new data
const finalState = { ...newData };

// Access existing Notion properties
const existingProperties = existingPage.properties;

// Iterate through existing Notion properties
for (const propName in existingProperties) {
  // Retain existing values if not provided in the new data
  if (!finalState.hasOwnProperty(propName)) {
    const prop = existingProperties[propName];
    let value = null;

    // Extract simple values from complex Notion property objects
    switch (prop.type) {
      case 'number':
        value = prop.number;
        break;
      case 'rich_text':
      case 'title':
        value = prop[prop.type] && prop[prop.type][0] ? prop[prop.type][0].plain_text : null;
        break;
      case 'checkbox':
        value = prop.checkbox;
        break;
      case 'select':
        value = prop.select ? prop.select.name : null;
        break;
    }

    // Update final object with the existing value
    finalState[propName] = value;
  }
}

// Inject page_id if missing from new data
if (!finalState.page_id) {
    finalState.page_id = existingPage.id;
}

// Return the merged data object
return finalState;
